+
+/**
+ * Priority levels for notification delivery.
+ */
+export type NotificationPriority = 'low' | 'normal' | 'high';
+
+/**
+ * Payload for creating a notification. Passed to adapters for delivery.
+ */
+export interface NotificationPayload {
+  recipient: string;
+  subject: string;
+  body: string;
+  notificationType: NotificationType;
+  channel: NotificationChannel;
+  priority: NotificationPriority;
+  metadata?: Record<string, string>;
+}
+
+/**
+ * A stored notification record. Created after a notification is dispatched.
+ */
+export interface Notification {
+  id: string;
+  recipient: string;
+  subject: string;
+  body: string;
+  notificationType: NotificationType;
+  channel: NotificationChannel;
+  priority: NotificationPriority;
+  status: 'pending' | 'sent' | 'failed';
+  metadata?: Record<string, string>;
+  createdAt: Date;
+  sentAt?: Date;
+}
+
+/**
+ * Result returned by adapters after attempting delivery.
+ */
+export interface NotificationResult {
+  success: boolean;
+  channel: NotificationChannel;
+  error?: string;
+}
+
