/**
 * Notification model and related types.
 *
 * These types form the foundation of the notification system. All notification
 * adapters and services operate on these types.
 */

/**
 * The type of notification being sent. Determines content formatting and routing.
 */
export type NotificationType =
  | 'order_confirmation'
  | 'order_status_update'
  | 'welcome'
  | 'account_updated';

/**
 * Delivery channels for notifications. Each channel has a corresponding adapter.
 */
export type NotificationChannel = 'email' | 'in_app' | 'webhook';

/**
 * Priority levels for notification delivery.
 */
export type NotificationPriority = 'low' | 'normal' | 'high';

/**
 * Payload for creating a notification. Passed to adapters for delivery.
 */
export interface NotificationPayload {
  recipient: string;
  subject: string;
  body: string;
  notificationType: NotificationType;
  channel: NotificationChannel;
  priority: NotificationPriority;
  metadata?: Record<string, string>;
}

/**
 * A stored notification record. Created after a notification is dispatched.
 */
export interface Notification {
  id: string;
  recipient: string;
  subject: string;
  body: string;
  notificationType: NotificationType;
  channel: NotificationChannel;
  priority: NotificationPriority;
  status: 'pending' | 'sent' | 'failed';
  metadata?: Record<string, string>;
  createdAt: Date;
  sentAt?: Date;
}

/**
 * Result returned by adapters after attempting delivery.
 */
export interface NotificationResult {
  success: boolean;
  channel: NotificationChannel;
  error?: string;
}

/**
 * Interface that all notification adapters must implement.
 *
 * CONSTRAINT: Every delivery channel (email, webhook, in-app, etc.) must have
 * a corresponding adapter that implements this interface. Adapters are registered
 * with the NotificationService and dispatched based on the notification's channel.
 */
export interface NotificationAdapter {
  /** The channel this adapter handles. */
  readonly channel: NotificationChannel;

  /**
   * Send a notification through this adapter's channel.
   * Must return a result indicating success or failure.
   */
  send(payload: NotificationPayload): Promise<NotificationResult>;
}

/**
 * Email notification adapter.
 *
 * Implements the NotificationAdapter interface for email delivery.
 * Currently stubbed — the send method logs and returns success without
 * actually sending email. Replace the body of send() with a real email
 * provider (SMTP, SendGrid, SES, etc.) when ready.
 *
 * CONSTRAINT: All adapters must implement the NotificationAdapter interface
 * from src/models/notification.ts. Register adapters with NotificationService
 * via registerAdapter().
 */

import type {
  NotificationAdapter,
  NotificationPayload,
  NotificationResult,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * Configuration for the email adapter.
 */
export interface EmailAdapterConfig {
  /** Sender address for outgoing emails. */
  fromAddress: string;
  /** Optional reply-to address. */
  replyToAddress?: string;
}

export class EmailAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');

  constructor(private config: EmailAdapterConfig) {}

  /**
   * Send a notification via email.
   *
   * Currently a stub that logs the email and returns success.
   * Replace with real email provider integration.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    this.logger.info(
      `Sending email to ${payload.recipient}: "${payload.subject}" (from: ${this.config.fromAddress})`,
    );

    // TODO: Replace with real email provider (SMTP, SendGrid, SES, etc.)
    // Example integration point:
    //   await emailProvider.send({
    //     from: this.config.fromAddress,
    //     replyTo: this.config.replyToAddress,
    //     to: payload.recipient,
    //     subject: payload.subject,
    //     body: payload.body,
    //   });

    return {
      success: true,
      channel: this.channel,
    };
  }
}

